export class AsyncLock {
    constructor() {
        this.locked = false;
        this.queue = [];
    }
    async acquire() {
        if (!this.locked) {
            this.locked = true;
            return;
        }
        return new Promise(resolve => { this.queue.push(resolve); });
    }
    release() {
        const next = this.queue.shift();
        if (next) {
            next();
        }
        else {
            this.locked = false;
        }
    }
}
